public class Main {
	public static void main(String[] args) {

		// Create a Scanner object to read input from the console
		Scanner sc = new Scanner(System.in);

		// Read two integer inputs from the user
		int a = sc.nextInt();
		int b = sc.nextInt();

		/* 
		 * The following series of if-else statements checks the values of 'a' and 'b'.
		 * Depending on their values, it prints a specific integer to the console.
		 * The logic seems to be based on a permutation of the numbers 1, 2, and 3.
		 * For each pair of inputs (a, b), the code prints the number that is not present in the pair.
		 */

		if (a == 1 && b == 2) {
			// If a is 1 and b is 2, print 3
			System.out.println(3);
		} else if (a == 1 && b == 3) {
			// If a is 1 and b is 3, print 2
			System.out.println(2);
		} else if (a == 2 && b == 3) {
			// If a is 2 and b is 3, print 1
			System.out.println(1);
		} else if (a == 2 && b == 1) {
			// If a is 2 and b is 1, print 3
			System.out.println(3);
		} else if (a == 3 && b == 1) {
			// If a is 3 and b is 1, print 2
			System.out.println(2);
		} else if (a == 3 && b == 2) {
			// If a is 3 and b is 2, print 1
			System.out.println(1);
		} else if (b == 1 && a == 2) {
			// If b is 1 and a is 2, print 3 (redundant due to symmetry)
			System.out.println(3);
		} else if (b == 1 && a == 3) {
			// If b is 1 and a is 3, print 2 (redundant due to symmetry)
			System.out.println(2);
		} else if (b == 2 && a == 3) {
			// If b is 2 and a is 3, print 1 (redundant due to symmetry)
			System.out.println(1);
		} else if (b == 2 && a == 1) {
			// If b is 2 and a is 1, print 3 (redundant due to symmetry)
			System.out.println(3);
		} else if (b == 3 && a == 1) {
			// If b is 3 and a is 1, print 2 (redundant due to symmetry)
			System.out.println(2);
		} else if (b == 3 && a == 2) {
			// If b is 3 and a is 2, print 1 (redundant due to symmetry)
			System.out.println(1);
		}

	}
}

